import React, { useState, useEffect, useRef } from 'react';

export default function SpeedDial({ actions }) {
  const [open, setOpen] = useState(false);
  const root = useRef(null);

  useEffect(() => {
    const onDoc = (e) => {
      if (root.current && !root.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener('mousedown', onDoc);
    return () => document.removeEventListener('mousedown', onDoc);
  }, []);

  const run = (a) => {
    a.onClick();
    setOpen(false);
  };

  const fab = {
    width: 56,
    height: 56,
    borderRadius: '50%',
    border: 'none',
    background: '#2563eb',
    color: '#fff',
    fontSize: 28,
    cursor: 'pointer',
    boxShadow: '0 4px 14px rgba(0,0,0,0.3)',
    transition: 'transform 0.2s',
    transform: open ? 'rotate(45deg)' : 'none',
  };

  return (
    <div ref={root} style={{ position: 'absolute', right: 24, bottom: 24, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 12 }}>
      <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 12 }}>
        {actions.map((a, i) => (
          <button
            key={a.label}
            onClick={() => run(a)}
            title={a.label}
            aria-label={a.label}
            style={{
              width: 44,
              height: 44,
              borderRadius: '50%',
              border: 'none',
              background: '#fff',
              fontSize: 18,
              cursor: 'pointer',
              boxShadow: '0 2px 8px rgba(0,0,0,0.2)',
              transition: 'opacity 0.2s, transform 0.2s',
              transitionDelay: `${(open ? i : actions.length - i) * 40}ms`,
              opacity: open ? 1 : 0,
              transform: open ? 'translateY(0)' : 'translateY(12px)',
              pointerEvents: open ? 'auto' : 'none',
            }}
          >
            {a.icon}
          </button>
        ))}
      </div>
      <button onClick={() => setOpen((o) => !o)} aria-label="Toggle menu" aria-expanded={open} style={fab}>+</button>
    </div>
  );
}

