import { Component, Input, HostListener, ElementRef } from '@angular/core';
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

interface Action { icon: string; label: string; onClick: () => void; }

@Component({
  selector: 'app-speed-dial',
  template: `
    <div style="position: absolute; right: 24px; bottom: 24px; display: flex; flex-direction: column; align-items: center; gap: 12px;">
      <div style="display: flex; flex-direction: column; align-items: center; gap: 12px;">
        <button
          *ngFor="let a of actions; let i = index"
          (click)="run(a)"
          [title]="a.label"
          [attr.aria-label]="a.label"
          [ngStyle]="itemStyle(i)"
          style="width: 44px; height: 44px; border-radius: 50%; border: none; background: #fff; font-size: 18px; cursor: pointer; box-shadow: 0 2px 8px rgba(0,0,0,0.2); transition: opacity 0.2s, transform 0.2s;"
        >{{ a.icon }}</button>
      </div>
      <button
        (click)="open = !open"
        aria-label="Toggle menu"
        [attr.aria-expanded]="open"
        [style.transform]="open ? 'rotate(45deg)' : 'none'"
        style="width: 56px; height: 56px; border-radius: 50%; border: none; background: #2563eb; color: #fff; font-size: 28px; cursor: pointer; box-shadow: 0 4px 14px rgba(0,0,0,0.3); transition: transform 0.2s;"
      >+</button>
    </div>
  `,
})
export class SpeedDialComponent {
  @Input() actions: Action[] = [];
  open = false;

  constructor(private host: ElementRef<HTMLElement>) {}

  run(a: Action): void {
    a.onClick();
    this.open = false;
  }

  itemStyle(i: number): Record<string, string> {
    return {
      'transition-delay': (this.open ? i : this.actions.length - i) * 40 + 'ms',
      opacity: this.open ? '1' : '0',
      transform: this.open ? 'translateY(0)' : 'translateY(12px)',
      'pointer-events': this.open ? 'auto' : 'none',
    };
  }

  @HostListener('document:click', ['$event'])
  onDoc(e: MouseEvent): void {
    if (!this.host.nativeElement.contains(e.target as Node)) {
      this.open = false;
    }
  }
}

@Component({
  selector: 'app-root',
  template: `
    <div style="font-family: sans-serif; padding: 20px; height: 320px; position: relative;">
      <h1>Speed Dial Demo</h1>
      <p style="color: #666;">Click the + button (bottom-right).</p>
      <app-speed-dial [actions]="actions"></app-speed-dial>
    </div>
  `,
})
export class AppComponent {
  actions: Action[] = [
    { icon: '✏️', label: 'Edit', onClick: () => window.alert('Edit') },
    { icon: '📋', label: 'Copy', onClick: () => window.alert('Copy') },
    { icon: '🗑️', label: 'Delete', onClick: () => window.alert('Delete') },
  ];
}

@NgModule({
  declarations: [AppComponent, SpeedDialComponent],
  imports: [BrowserModule],
  bootstrap: [AppComponent],
})
export class AppModule {}
